def solve():
    import sys
    from collections import deque

    data = sys.stdin.read().split("\n")
    r, c = map(int, data[0].split())
    grid = [data[1 + i] for i in range(r)]

    start = goal = None
    for i in range(r):
        for j in range(c):
            if grid[i][j] == "S":
                start = (i, j)
            elif grid[i][j] == "G":
                goal = (i, j)

    dist = [[-1] * c for _ in range(r)]
    dist[start[0]][start[1]] = 0
    q = deque([start])
    while q:
        y, x = q.popleft()
        if (y, x) == goal:
            break
        for dy, dx in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            ny, nx = y + dy, x + dx
            if 0 <= ny < r and 0 <= nx < c and grid[ny][nx] != "#" and dist[ny][nx] == -1:
                dist[ny][nx] = dist[y][x] + 1
                q.append((ny, nx))

    print(dist[goal[0]][goal[1]])

solve()
